using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=4e2+5;
int H,T,n,f[MAXN][MAXN],h[MAXN],t[MAXN],k[MAXN]; 
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	H=read(),T=read();
	n=read();
	FOR(i,1,n)
	{
		h[i]=read();
		t[i]=read();
		k[i]=read();
	}
	FOR(i,1,n)
	{
		ROF(j,H,h[i])
		{
			ROF(c,T,t[i])
			{
				f[j][c]=max(f[j-h[i]][c-t[i]]+k[i],f[j][c]);
			}
		}
	}
	write(f[H][T]);
    return false;
}
